-- Reconstruct Country from local_1.nation
CREATE VIEW "Country" AS
SELECT
    "local_1"."nation"."nation_id" AS "id",
    "local_1"."nation"."common_name" AS "name"
FROM "local_1"."nation";

-- Reconstruct League from local_1.competition
CREATE VIEW "League" AS
SELECT
    "local_1"."competition"."competition_id" AS "id",
    "local_1"."competition"."nation_id" AS "country_id",
    "local_1"."competition"."league_title" AS "name"
FROM "local_1"."competition";

