SELECT [PlayerAttributesAggressionAbove73].[__orig_rowid] AS __orig_rowid, [local_2].[PlayerAttributesAggressionAbove73].[AggressionAttributeIdAbove73], [local_2].[PlayerAttributesAggressionAbove73].[AttackingWorkRate], [local_2].[PlayerAttributesAggressionAbove73].[DefensiveWorkRate], [local_2].[PlayerAttributesAggressionAbove73].[AggressionRating], [local_2].[PlayerAttributesAggressionAbove73].[VisionRating] FROM [local_2].[PlayerAttributesAggressionAbove73]
